import React, {
  useState,
  Suspense,
  lazy,
  useEffect,
  useMemo,
  useRef,
} from "react";
import SiteHeader from "main/SiteHeader";
import EducationSection from "main/Education";
import Section from "main/Section";
import {
  Box,
  Button,
  Skeleton,
  Typography,
  useTheme,
  useMediaQuery,
} from "@mui/material";
import {
  personalInfo,
  education,
  experience,
  projects,
  volunteering,
} from "content/site/siteData";
import { useContentMode } from "./hooks/useContentMode";
import { generateId } from "main/utils";

const DetailPane = lazy(() => import("main/DetailPane"));
const DESKTOP_PANE_HEIGHT = "calc(100vh - 3rem)";

const SECTION_LINKS = [
  { id: "section-about", label: "About" },
  { id: "section-education", label: "Education" },
  { id: "section-experience", label: "Experience" },
  { id: "section-leadership", label: "Leadership" },
  { id: "section-projects", label: "Projects" },
];

const SectionIndex = ({ onJump, activeSectionId }) => {
  return (
    <Box
      sx={{
        position: "sticky",
        top: 0,
        zIndex: 2,
        py: 1,
        mb: 1,
        backgroundColor: { xs: "transparent", md: "background.paper" },
      }}
    >
      <Box
        sx={{
          display: "flex",
          flexWrap: "nowrap",
          alignItems: "center",
          gap: 0.25,
          overflowX: "scroll",
        }}
      >
        {SECTION_LINKS.map((section) => (
          <Button
            key={section.id}
            size="small"
            variant="text"
            disableRipple
            onClick={() => onJump(section.id)}
            sx={{
              textTransform: "none",
              minWidth: 0,
              flexShrink: 0,
              px: 0.75,
              py: 0.35,
              borderRadius: "0.5rem",
              color:
                activeSectionId === section.id
                  ? "text.primary"
                  : "text.secondary",
              fontWeight: activeSectionId === section.id ? 700 : 600,
              whiteSpace: "nowrap",
              opacity: activeSectionId === section.id ? 1 : 0.82,
              "&:hover": {
                backgroundColor: "action.hover",
                opacity: 1,
              },
            }}
          >
            {section.label}
          </Button>
        ))}
      </Box>
    </Box >
  );
};

const DetailPaneLoading = ({ width = "75%" }) => {
  return (
    <Box sx={{ width, p: 4 }}>
      <Skeleton variant="text" width="30%" height={36} />
      <Skeleton variant="text" width="55%" height={28} />
      <Skeleton variant="rounded" width="100%" height={180} sx={{ my: 2 }} />
      <Skeleton variant="text" width="96%" height={26} />
      <Skeleton variant="text" width="92%" height={26} />
      <Skeleton variant="text" width="88%" height={26} />
    </Box>
  );
};

const HomePage = () => {
  const theme = useTheme();
  const matches = useMediaQuery(theme.breakpoints.up("md"));

  const {
    selectedContent,
    selectedId,
    selectedProject,
    parentItem,
    selectedItem,
    handleSelect,
  } = useContentMode();

  const [activeSectionId, setActiveSectionId] = useState(SECTION_LINKS[0].id);
  const leftPaneRef = useRef(null);
  const latestExperienceId = useMemo(() => generateId(experience[0]), []);

  const randomProjectOptions = useMemo(() => {
    const nested = [...experience, ...volunteering].flatMap((item) =>
      (item.projects || []).map((proj) => ({
        id: generateId({
          ...proj,
          title: proj.projectName,
          organization: item.organization,
        }),
        title: proj.projectName,
      }))
    );
    const standalone = projects.map((project) => ({
      id: generateId(project),
      title: project.title,
    }));
    return [...nested, ...standalone];
  }, []);

  const [randomSuggestion, setRandomSuggestion] = useState(null);

  useEffect(() => {
    if (matches && !selectedId && randomProjectOptions.length) {
      const next =
        randomProjectOptions[
        Math.floor(Math.random() * randomProjectOptions.length)
        ];
      setRandomSuggestion(next);
    }
  }, [matches, selectedId, randomProjectOptions]);

  useEffect(() => {
    if (!matches || !leftPaneRef.current) return;

    const root = leftPaneRef.current;
    setActiveSectionId("section-about");

    const sections = SECTION_LINKS.map((section) => {
      const element = document.getElementById(section.id);
      return element ? { id: section.id, element } : null;
    }).filter(Boolean);
    if (!sections.length) return;

    const updateActiveSection = () => {
      const anchor = root.scrollTop + 100;
      let currentId = sections[0].id;

      for (const section of sections) {
        if (section.element.offsetTop <= anchor) {
          currentId = section.id;
        } else {
          break;
        }
      }

      setActiveSectionId(currentId);
    };

    updateActiveSection();
    root.addEventListener("scroll", updateActiveSection, { passive: true });
    window.addEventListener("resize", updateActiveSection);

    return () => {
      root.removeEventListener("scroll", updateActiveSection);
      window.removeEventListener("resize", updateActiveSection);
    };
  }, [matches]);

  const handleClose = () => {
    handleSelect(null);
  };

  const aboutItem = { title: "Leo Liu" };
  const isAboutSelected = selectedId === "leo-liu";

  const detailPaneContent =
    isAboutSelected ? (
      <SiteHeader personalInfo={personalInfo} variant="detailPane" />
    ) : (
      selectedContent
    );

  const isMobileSelectedDetailMode =
    !matches &&
    (isAboutSelected ||
      (Boolean(selectedContent) && !selectedItem?.projects?.length));
  const isMobileListMode = !matches && !isMobileSelectedDetailMode;

  useEffect(() => {
    if (matches || !isMobileListMode) return;

    setActiveSectionId("section-about");

    const sections = SECTION_LINKS.map((section) => {
      const element = document.getElementById(section.id);
      return element ? { id: section.id, element } : null;
    }).filter(Boolean);
    if (!sections.length) return;

    const updateActiveSection = () => {
      const anchor = window.scrollY + 120;
      let currentId = sections[0].id;

      for (const section of sections) {
        if (section.element.offsetTop <= anchor) {
          currentId = section.id;
        } else {
          break;
        }
      }

      setActiveSectionId(currentId);
    };

    updateActiveSection();
    window.addEventListener("scroll", updateActiveSection, { passive: true });
    window.addEventListener("resize", updateActiveSection);

    return () => {
      window.removeEventListener("scroll", updateActiveSection);
      window.removeEventListener("resize", updateActiveSection);
    };
  }, [matches, isMobileListMode]);

  const renderSectionList = ({
    showSectionIndex = false,
    folderOverviewMode = false,
  } = {}) => (
    <>
      {showSectionIndex && (
        <SectionIndex
          onJump={handleJumpToSection}
          activeSectionId={activeSectionId}
        />
      )}
      <Section
        sectionTitle="About Me"
        items={[aboutItem]}
        selectedId={selectedId}
        onSelect={handleSelect}
        sectionId="section-about"
      />
      <EducationSection
        educationData={education}
        selectedId={selectedId}
        onSelect={handleSelect}
        sectionId="section-education"
      />
      <Section
        sectionTitle="Experience"
        items={experience}
        selectedId={selectedId}
        onSelect={handleSelect}
        showOverviewInFolder={folderOverviewMode}
        sectionId="section-experience"
      />
      <Section
        sectionTitle="Leadership"
        items={volunteering}
        selectedId={selectedId}
        onSelect={handleSelect}
        showOverviewInFolder={folderOverviewMode}
        sectionId="section-leadership"
      />
      <Section
        sectionTitle="Projects"
        items={projects}
        selectedId={selectedId}
        onSelect={handleSelect}
        sectionId="section-projects"
      />
    </>
  );

  const handleJumpToSection = (sectionId) => {
    setActiveSectionId(sectionId);
    const section = document.getElementById(sectionId);
    if (section) {
      section.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  return (
    <>
      <Box sx={{ textAlign: "start" }}>
        {matches ? (
          <Box
            sx={{
              display: "flex",
              alignItems: "flex-start",
              gap: 0,
              height: DESKTOP_PANE_HEIGHT,
              overflow: "hidden",
              borderRadius: "1rem",
              border: (theme) =>
                `1px solid ${theme.palette.divider}`,
              bgcolor: "background.paper",
              transition: theme.transitions.create(["gap", "height"], {
                duration: theme.transitions.duration.standard,
                easing: theme.transitions.easing.easeInOut,
              }),
            }}
          >
            <Box
              sx={{
                display: "block",
                width: "25%",
                minWidth: "320px",
                maxWidth: "390px",
                height: DESKTOP_PANE_HEIGHT,
                borderRight: (theme) =>
                  `1px solid ${theme.palette.divider}`,
                transition: theme.transitions.create("width", {
                  duration: theme.transitions.duration.complex,
                  easing: theme.transitions.easing.easeInOut,
                }),
              }}
            >
              <Box
                ref={leftPaneRef}
                sx={{
                  p: 3,
                  pt: 0,
                  height: "100%",
                  overflowY: "auto",
                  overflowX: "hidden",
                }}
              >
                {renderSectionList({
                  showSectionIndex: true,
                  folderOverviewMode: false,
                })}
              </Box>
            </Box>

            <Suspense fallback={<DetailPaneLoading />}>
              <DetailPane
                isBlogMode={false}
                selectedContent={detailPaneContent}
                selectedProject={selectedProject}
                parentItem={parentItem}
                selectedItem={selectedItem}
                selectedId={selectedId}
                onClose={handleClose}
                desktopHeight={DESKTOP_PANE_HEIGHT}
                emptyState={
                  (
                    <>
                      <Typography
                        variant="h6"
                        sx={{
                          color: "text.primary",
                          textAlign: "center",
                          fontWeight: 700,
                        }}
                      >
                        Pick something on the left to explore details
                      </Typography>
                      <Typography variant="body2" color="text.secondary" textAlign="center">
                        Rich mode is still here—use a quick action below if you want a guided shortcut.
                      </Typography>
                      <Box
                        sx={{
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          flexWrap: "wrap",
                          gap: 1,
                        }}
                      >
                        {randomSuggestion && (
                          <Button
                            variant="text"
                            onClick={() => handleSelect(randomSuggestion.id)}
                            disableRipple
                            sx={{ textTransform: "none", borderRadius: "999px", px: 1.25 }}
                          >
                            Surprise me: {randomSuggestion.title}
                          </Button>
                        )}
                        <Button
                          variant="text"
                          onClick={() => handleSelect(latestExperienceId)}
                          disableRipple
                          sx={{ textTransform: "none", borderRadius: "999px", px: 1.25 }}
                        >
                          Open latest experience
                        </Button>
                      </Box>
                      <Box>
                        <Box
                          sx={{
                            width: "420px",
                            maxWidth: "100%",
                            height: "240px",
                            backgroundImage: "url(/photos/optimized/IMG_0206.jpg)",
                            backgroundSize: "cover",
                            backgroundPosition: "center",
                            borderRadius: "1rem",
                            overflow: "hidden",
                            opacity: 0.92,
                          }}
                        />
                        <Typography
                          variant="body1"
                          paragraph
                          color="text.secondary"
                          textAlign="end"
                          sx={{ mt: "0.5rem" }}
                        >
                          Kelowna, BC
                        </Typography>
                      </Box>
                    </>
                  )
                }
              />
            </Suspense>
          </Box>
        ) : isMobileSelectedDetailMode && detailPaneContent ? (
          <Suspense fallback={<DetailPaneLoading width="100%" />}>
            <DetailPane
              isBlogMode={false}
              selectedContent={detailPaneContent}
              selectedProject={selectedProject}
              parentItem={parentItem}
              selectedItem={selectedItem}
              selectedId={selectedId}
              onClose={handleClose}
              desktopHeight="auto"
              disableContainerGutters
            />
          </Suspense>
        ) : (
          renderSectionList({
            showSectionIndex: true,
            folderOverviewMode: "selected-only",
          })
        )}
      </Box>
    </>
  );
};

export default HomePage;
